# Module providing mathematical utility functions and classes

class Calculator:
    name: str

    def __init__(self, name: str):
        self.name = name

    def add(self, a: int, b: int) -> int:
        return a + b

    def multiply(self, a: int, b: int) -> int:
        return a * b

def factorial(n: int) -> int:
    if n <= 1:
        return 1
    result: int = 1
    i: int = 2
    while i <= n:
        result = result * i
        i += 1
    return result

def is_even(x: int) -> bool:
    return x % 2 == 0

