# Module providing geometric shapes and calculations
from math_utils import Calculator

class Rectangle:
    width: int
    height: int
    calc: Calculator

    def __init__(self, w: int, h: int):
        self.width = w
        self.height = h
        self.calc = Calculator("RectCalc")

    def area(self) -> int:
        return self.calc.multiply(self.width, self.height)

    def perimeter(self) -> int:
        side_sum: int = self.calc.add(self.width, self.height)
        return self.calc.multiply(side_sum, 2)
